local LCityBase = require("LApp.gameplay.city.base.LCityBase")
---@class LCityMonsterHud:LCityBase
local LCityMonsterHud = classX("LCityMonsterHud", LCityBase)
local typeOfFollowTransform = typeof(ProjectX.CFollowTransform)
function LCityMonsterHud:ctor()
    LCityBase.ctor(self)
    self._refId = nil
    self._monsterObj = nil
    self._hudObj = nil
    ---@type LCityMonsterMgr
    self._monsterMgr = nil
    self._followTransform = nil

    self._defaultCameraSize = 7.5
    self._curCameraSize = self._defaultCameraSize
    self._scaleRadio = 0.8 / (GameTable.BuildingConfigRef.cameraMaxRate - self._defaultCameraSize)
    self._followRadio = -3
end

function LCityMonsterHud:Initialize()
    LCityBase.Initialize(self)
end
function LCityMonsterHud:ShowHUD()
    ShowObject(self._hudObj.gameObject,true)
end
function LCityMonsterHud:HideHUD()
    ShowObject(self._hudObj.gameObject,false)
end
function LCityMonsterHud:SetHud(refId,monsterObj,hudObj,mgr)
    self._refId = refId
    self._monsterObj = monsterObj
    self._hudObj = hudObj
    self._monsterMgr = mgr
    self:InitComponent()
end
function LCityMonsterHud:InitComponent()

    self._followTransform = self._hudObj.gameObject:GetComponent(typeOfFollowTransform)
    if(self._followTransform == nil)then
        self._followTransform = self._hudObj.gameObject:AddComponent(typeOfFollowTransform)
    end
    self._iconInfo = FindChild(self._hudObj,"IconInfo")
    local monsterRef = GameTable.CityMonsterRef[self._refId]
    local arr = string.split(monsterRef.ModelId[1],"=")
    local monsterId = checknumber(arr[1])
    local heroRef = GameTable.CharacterEffectRef[monsterId]
    local monsterRes = heroRef.model
    local path = monsterRes.."/TopNode"
    local targetTrans = LxUiHelper.FindChild(self._monsterObj.transform,path)
    self._followTransform:SetTarget(targetTrans)
    if(ModuleCenter.Story:IsNewbieRunning())then
        self:HideHUD()
    end
end
function LCityMonsterHud:RefreshShowHud(show)
    if(ModuleCenter.Story:IsNewbieRunning())then
        self:HideHUD()
        return
    end
    ShowObject(self._hudObj.gameObject,show)
end
function LCityMonsterHud:Dispose()
    if IsValid(self._hudObj) then
        LxResUtil.DestroyObject(self._hudObj.gameObject)
    end
    self._followTransform = nil
    LCityBase.Dispose(self)
end
function LCityMonsterHud:OnUpdate(deltaTime)
    if(CtrlCenter.City:GetCityView():GetCameraSize() == self._defaultCameraSize)then
        return
    end
    self._curCameraSize = CtrlCenter.City:GetCityView():GetCameraSize()
    local scale = 1 -(self._curCameraSize - self._defaultCameraSize) * self._scaleRadio
    if(scale > 1)then
        scale = 1
    end
    self._iconInfo.transform.localScale = Vector3(scale,scale,scale)
    local followY = (self._curCameraSize - self._defaultCameraSize) * self._followRadio
    self._followTransform:SetOffset(Vector2(0,followY))
end
return LCityMonsterHud